-- ============================================
-- Legislacao full-site: celina-leao / Camara Dados Abertos / projetos_lei
-- Coverage ampliado parcial: Lote A autoria principal Camara
-- ============================================
-- Fonte oficial: Camara dos Deputados - Dados Abertos
--   https://dadosabertos.camara.leg.br/api/v2/deputados/204380
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}/autores
--
-- Artefato de auditoria:
--   fonte interna de curadoria
--
-- Coverage:
--   coverage_id    = celina-leao-camara-autoria-principal-ampliado-parcial-lote-a-20260506
--   coverage_scope = inventario_ampliado_parcial_camara_autoria_principal_lote_a_20260506
--
-- Filtro factual: das 100 rows Camara legacy existentes, somente 78
-- foram marcadas com coverage_id porque a API oficial confirmou
-- idDeputado=204380, tipo Deputado(a), ordemAssinatura=1.
-- 22 rows permanecem sem coverage por coautoria/sem autoria verificavel.
--
-- Esta migration NAO escreve em legislacao_mandato_executivo.
-- Esta migration NAO insere, deleta ou trunca rows.
-- ============================================

DO $$
DECLARE
  cand_id uuid;
  total_pl int;
  target_present int;
  target_with_other_coverage int;
  lme_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'celina-leao';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'celina-leao: candidato ausente neste banco local/CI minimo; coverage Camara pulado';
    RETURN;
  END IF;

  SELECT count(*) INTO total_pl FROM projetos_lei WHERE candidato_id = cand_id;
  IF total_pl <> 100 THEN
    RAISE EXCEPTION 'Pre-condicao celina-leao: esperadas 100 rows legacy em projetos_lei, encontradas %', total_pl;
  END IF;

  SELECT count(*) INTO target_present
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND fonte = 'Camara'
    AND proposicao_id_api IN ('2345160', '2345147', '2344824', '2345154', '2345153', '2345145', '2345144', '2345138', '2344804', '2344803', '2344802', '2344799', '2344798', '2344796', '2344790', '2342339', '2342338', '2342299', '2341876', '2341875', '2341439', '2340798', '2344818', '2344792', '2342301', '2341487', '2334922', '2334623', '2332646', '2331030', '2326310', '2324373', '2321724', '2321348', '2320935', '2342337', '2340373', '2336092', '2332707', '2324378', '2321755', '2321029', '2319653', '2318953', '2334639', '2333539', '2332456', '2330053', '2326295', '2324630', '2321640', '2319764', '2318955', '2334648', '2334473', '2326309', '2323654', '2321723', '2321347', '2320407', '2319256', '2332462', '2326296', '2323236', '2321722', '2321115', '2320088', '2318958', '2345146', '2341873', '2334643', '2344800', '2340532', '2344801', '2336093', '2345155', '2344795', '2334635');
  IF target_present <> 78 THEN
    RAISE EXCEPTION 'Pre-condicao celina-leao: esperadas 78 rows alvo Camara presentes, encontradas %', target_present;
  END IF;

  SELECT count(*) INTO target_with_other_coverage
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND proposicao_id_api IN ('2345160', '2345147', '2344824', '2345154', '2345153', '2345145', '2345144', '2345138', '2344804', '2344803', '2344802', '2344799', '2344798', '2344796', '2344790', '2342339', '2342338', '2342299', '2341876', '2341875', '2341439', '2340798', '2344818', '2344792', '2342301', '2341487', '2334922', '2334623', '2332646', '2331030', '2326310', '2324373', '2321724', '2321348', '2320935', '2342337', '2340373', '2336092', '2332707', '2324378', '2321755', '2321029', '2319653', '2318953', '2334639', '2333539', '2332456', '2330053', '2326295', '2324630', '2321640', '2319764', '2318955', '2334648', '2334473', '2326309', '2323654', '2321723', '2321347', '2320407', '2319256', '2332462', '2326296', '2323236', '2321722', '2321115', '2320088', '2318958', '2345146', '2341873', '2334643', '2344800', '2340532', '2344801', '2336093', '2345155', '2344795', '2334635')
    AND coverage_id IS NOT NULL
    AND coverage_id <> 'celina-leao-camara-autoria-principal-ampliado-parcial-lote-a-20260506';
  IF target_with_other_coverage <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao celina-leao: % rows alvo ja tem coverage_id divergente', target_with_other_coverage;
  END IF;

  SELECT count(*) INTO lme_count FROM legislacao_mandato_executivo WHERE candidato_id = cand_id;
  IF lme_count <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao celina-leao: legislacao_mandato_executivo deve permanecer 0, encontrado %', lme_count;
  END IF;
END $$;

